  EXPECT_LE(snapshot.statsBeforeGuard.current_usage, snapshot.statsAfterGuard.current_usage);
  EXPECT_GE(snapshot.statsAfterGuard.current_usage, snapshot.statsBeforeGuard.current_usage);
}

}  // namespace test_reaction

