    reaction::memory::StackMonitor::UsageStats statsAfterGuard;
    bool templateAllocationAllowed;
    bool runtimeAllocationAllowed;
    bool guardHeld;
    bool allocationBlockedWhileGuardHeld;
};

inline StackLimitSnapshot test_stack_monitor_limits() {
    using namespace reaction::memory;

    StackLimitSnapshot snapshot;

    // 1. Enable monitoring
    StackMonitor::enableMonitoring();

    // 2. Initialize stack monitor
    StackMonitor::initialize();

    // 3. Get usage statistics before guard
    snapshot.statsBeforeGuard = StackMonitor::getUsageStats();

    // 4. Check if template allocation is allowed
    constexpr size_t TEST_SIZE = 1024;
    snapshot.templateAllocationAllowed = StackMonitor::canAllocate<TEST_SIZE>();

    // 5. Check if runtime allocation is allowed
    snapshot.runtimeAllocationAllowed = StackMonitor::canAllocate(TEST_SIZE);

    // 6. Create large StackGuard instance
    constexpr size_t LARGE_SIZE = 4096;
    StackGuard<LARGE_SIZE> guard;

    // 7. Check if guard succeeded
    snapshot.guardHeld = guard.isHeld();

    // 8. Check if allocation blocked while guard is held
    snapshot.allocationBlockedWhileGuardHeld = !StackMonitor::canAllocate<TEST_SIZE>();

    // 9. Get usage statistics after guard
    snapshot.statsAfterGuard = StackMonitor::getUsageStats();

    // 10. Return stack limit snapshot
    return snapshot;
}

